NEW += '                        &bull; <strong>Count paths with sum = K</strong> &mdash; Stage 3 | O(n) | DFS with prefix-sum hashmap + backtracking<br>\n'
NEW += '                        &bull; <strong>Maximum XOR path in tree</strong> &mdash; Stage 4 | O(n log V) | XOR prefix from root + trie<br><br>\n'
NEW += '                        <strong>Group 7 &mdash; Top-2 Arms Rerooting:</strong><br>\n'
NEW += '                        &bull; <strong>Tree diameter (general n-ary)</strong> &mdash; Stage 2 | O(n) | top-2 arm depths; prevent same child for both arms<br>\n'
NEW += '                        &bull; <strong>Maximum path sum (any path)</strong> &mdash; Stage 2 | O(n) | arm = max(0, best child arm) + val<br>\n'
NEW += '                        &bull; <strong>Maximum average path</strong> &mdash; Stage 4 | O(n log V) | binary search on answer + re-weight edges<br><br>\n'
NEW += '                        <strong>Group 8 &mdash; Centroid Decomp / Virtual Tree:</strong><br>\n'
