NEW += '                        <strong>Stage 2 (MIS):</strong> dp[v][1] = val[v] + &sum; dp[c][0] &nbsp;&nbsp; dp[v][0] = &sum; max(dp[c][0], dp[c][1])<br>\n'
NEW += '                        Base: dp[leaf][1] = val[leaf], dp[leaf][0] = 0 | Preferred: bottom-up post-order<br><br>\n'
NEW += '                        <strong>Stage 3 (Camera):</strong> dp[v][s] where s &isin; &#123;0=uncovered, 1=has_camera, 2=covered_by_child&#125;<br>\n'
NEW += '                        dp[v][1] = 1 + min over child combos where v has camera; dp[v][2] = min where &ge;1 child has state 1; dp[v][0] = min where all children have state 2<br>\n'
NEW += '                        Base: dp[leaf][0]=0, dp[leaf][1]=1, dp[leaf][2]=INF<br><br>\n'
NEW += '                        <strong>Group 5: Tree Knapsack &mdash; dp[v][k]</strong><br>\n'
NEW += '                        <strong>Stage 3:</strong> dp[v][k] = max value using exactly k nodes in subtree of v<br>\n'
